mapper.select:
SELECT t.id, t.task_name, t.department, t.task_type, t.original_file_name, t.file_size, t.total_count, t.success_count, t.failed_count, t.pending_count, t.status, t.error_message, t.notify_type, t.notify_target, t.retry_count, t.start_time, t.end_time, t.created_by_name, t.created_time FROM batch_task t WHERE t.deleted = 0
AND t.status = #{status}
AND t.department = #{department}
AND t.created_by = #{createdBy}
AND DATE(t.created_time) >= #{startDate}
AND DATE(t.created_time) <= #{endDate}
ORDER BY t.created_time DESC
